```typescript
class UserService {
    updateEmail(userId: string, newEmail: string) {
        this.db.updateUser(userId, { email: newEmail });
        this.emailService.send(newEmail, 'Email updated');
        this.smsService.send(this.db.getUser(userId).phone, 'Email updated');
        this.pushService.notify(userId, 'Email updated');
        this.auditLog.write(`User ${userId} changed email`);
    }

    updatePassword(userId: string, newPassword: string) {
        this.db.updateUser(userId, { password: hash(newPassword) });
        this.emailService.send(this.db.getUser(userId).email, 'Password changed');
        this.smsService.send(this.db.getUser(userId).phone, 'Password changed');
        this.pushService.notify(userId, 'Password changed');
        this.auditLog.write(`User ${userId} changed password`);
        this.securityService.revokeTokens(userId);
    }

    deactivateAccount(userId: string) {
        this.db.updateUser(userId, { active: false });
        this.emailService.send(this.db.getUser(userId).email, 'Account deactivated');
        this.smsService.send(this.db.getUser(userId).phone, 'Account deactivated');
        this.pushService.notify(userId, 'Account deactivated');
        this.auditLog.write(`User ${userId} deactivated`);
        this.sessionService.killSessions(userId);
    }
}
